#include <stdlib.h>

int main() {
    int a, b;
    int *p = &a;
    int *q = &a;  // q aliases p (both point to a)
    int *r = &b;  // r does not alias p or q

    *p = 10;
    *q = 20;      // clobbers *p since q aliases p
    *r = 30;      // does not clobber *p

    int x = *p;   // reaching defs: *p=10 and *q=20 (may-alias)
    int y = *r;   // reaching def: *r=30 only
    return x + y;
}
